    public void handleTicker(Client client, Object message)
    {
        //
        // market/snapshot
        //
        // updates come in every 2 sec unless there
        // were no changes since the previous update
        //
        //     {
        //         "data": {
        //             "sequence": "1545896669291",
        //             "data": {
        //                 "trading": true,
        //                 "symbol": "KCS-BTC",
        //                 "buy": 0.00011,
        //                 "sell": 0.00012,
        //                 "sort": 100,
        //                 "volValue": 3.13851792584, // total
        //                 "baseCurrency": "KCS",
        //                 "market": "BTC",
        //                 "quoteCurrency": "BTC",
        //                 "symbolCode": "KCS-BTC",
        //                 "datetime": 1548388122031,
        //                 "high": 0.00013,
        //                 "vol": 27514.34842,
        //                 "low": 0.0001,
        //                 "changePrice": -1.0e-5,
        //                 "changeRate": -0.0769,
        //                 "lastTradedPrice": 0.00012,
        //                 "board": 0,
        //                 "mark": 0
        //             }
        //         },
        //         "subject": "trade.snapshot",
        //         "topic": "/market/snapshot:KCS-BTC",
        //         "type": "message"
        //     }
        //
        // market/ticker
        //
        //     {
        //         "type": "message",
        //         "topic": "/market/ticker:BTC-USDT",
        //         "subject": "trade.ticker",
        //         "data": {
        //             "bestAsk": "62163",
        //             "bestAskSize": "0.99011388",
        //             "bestBid": "62162.9",
        //             "bestBidSize": "0.04794181",
        //             "price": "62162.9",
        //             "sequence": "1621383371852",
        //             "size": "0.00832274",
        //             "time": 1634641987564
        //         }
        //     }
        //
        Object topic = this.safeString(message, "topic");
        Object market = null;
        if (Helpers.isTrue(!Helpers.isEqual(topic, null)))
        {
            Object parts = Helpers.split(topic, ":");
            Object first = this.safeString(parts, 1);
            Object marketId = null;
            if (Helpers.isTrue(Helpers.isEqual(first, "all")))
            {
                marketId = this.safeString(message, "subject");
            } else
            {
                marketId = first;
            }
            market = this.safeMarket(marketId, market, "-");
        }
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object rawTicker = this.safeValue(data, "data", data);
        Object ticker = this.parseTicker(rawTicker, market);
        Object symbol = Helpers.GetValue(ticker, "symbol");
        Helpers.addElementToObject(this.tickers, symbol, ticker);
        Object messageHash = Helpers.add("ticker:", symbol);
        client.resolve(ticker, messageHash);
        // watchTickers
        Object allTickers = new java.util.HashMap<String, Object>() {{}};
        Helpers.addElementToObject(allTickers, symbol, ticker);
        client.resolve(allTickers, "tickers");
    }

