    public void handleOHLCV(Client client, Object message)
    {
        //
        //     {
        //         "data": {
        //             "symbol": "BTC-USDT",
        //             "candles": [
        //                 "1624881240",
        //                 "34138.8",
        //                 "34121.6",
        //                 "34138.8",
        //                 "34097.9",
        //                 "3.06097133",
        //                 "104430.955068564"
        //             ],
        //             "time": 1624881284466023700
        //         },
        //         "subject": "trade.candles.update",
        //         "topic": "/market/candles:BTC-USDT_1min",
        //         "type": "message"
        //     }
        //
        Object data = this.safeValue(message, "data", new java.util.HashMap<String, Object>() {{}});
        Object marketId = this.safeString(data, "symbol");
        Object candles = this.safeValue(data, "candles", new java.util.ArrayList<Object>(java.util.Arrays.asList()));
        Object topic = this.safeString(message, "topic");
        Object parts = Helpers.split(topic, "_");
        Object interval = this.safeString(parts, 1);
        // use a reverse lookup in a static map instead
        Object timeframe = this.findTimeframe(interval);
        Object market = this.safeMarket(marketId);
        Object symbol = Helpers.GetValue(market, "symbol");
        Object messageHash = Helpers.add(Helpers.add(Helpers.add("candles:", symbol), ":"), timeframe);
        
        Helpers.addElementToObject(this.ohlcvs, symbol, this.safeValue(this.ohlcvs, symbol, new java.util.HashMap<String, Object>() {{}}));
        Object stored = this.safeValue(Helpers.GetValue(this.ohlcvs, symbol), timeframe);
        if (Helpers.isTrue(Helpers.isEqual(stored, null)))
        {
            Object limit = this.safeInteger(this.options, "OHLCVLimit", 1000);
            stored = new ArrayCache.ArrayCacheByTimestamp(((Number)limit).intValue());
            Helpers.addElementToObject(Helpers.GetValue(this.ohlcvs, symbol), timeframe, stored);
        }
        Object ohlcv = this.parseOHLCV(candles, market);
        Helpers.callDynamically(stored, "append", new Object[]{ohlcv});
        client.resolve(stored, messageHash);
    }

