    /**
     * @method
     * @name kucoin#watchOrders
     * @description watches information on multiple orders made by the user
     * @see https://www.kucoin.com/docs/websocket/spot-trading/private-channels/private-order-change
     * @see https://www.kucoin.com/docs/websocket/spot-trading/private-channels/stop-order-event
     * @param {string} symbol unified market symbol of the market orders were made in
     * @param {int} [since] the earliest time in ms to fetch orders for
     * @param {int} [limit] the maximum number of order structures to retrieve
     * @param {object} [params] extra parameters specific to the exchange API endpoint
     * @param {boolean} [params.trigger] trigger orders are watched if true
     * @returns {object[]} a list of [order structures]{@link https://docs.ccxt.com/?id=order-structure}
     */
    public java.util.concurrent.CompletableFuture<Object> watchOrders(Object... optionalArgs)
    {

        return java.util.concurrent.CompletableFuture.supplyAsync(() -> {

            Object symbol = Helpers.getArg(optionalArgs, 0, null);
            Object since = Helpers.getArg(optionalArgs, 1, null);
            Object limit = Helpers.getArg(optionalArgs, 2, null);
            Object parameters = Helpers.getArg(optionalArgs, 3, new java.util.HashMap<String, Object>() {{}});
            (this.loadMarkets()).join();
            Object trigger = this.safeValue2(parameters, "stop", "trigger");
            parameters = this.omit(parameters, new java.util.ArrayList<Object>(java.util.Arrays.asList("stop", "trigger")));
            Object url = (this.negotiate(true)).join();
            Object topic = ((Helpers.isTrue(trigger))) ? "/spotMarket/advancedOrders" : "/spotMarket/tradeOrders";
            Object request = new java.util.HashMap<String, Object>() {{
                put( "privateChannel", true );
            }};
            Object messageHash = "orders";
            if (Helpers.isTrue(!Helpers.isEqual(symbol, null)))
            {
                Object market = this.market(symbol);
                symbol = Helpers.GetValue(market, "symbol");
                messageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
            }
            Object orders = (this.subscribe(url, messageHash, topic, this.extend(request, parameters))).join();
            if (Helpers.isTrue(this.newUpdates))
            {
                limit = Helpers.callDynamically(orders, "getLimit", new Object[]{symbol, limit});
            }
            return this.filterBySymbolSinceLimit(orders, symbol, since, limit, true);
        }, io.github.ccxt.Exchange.VIRTUAL_EXECUTOR);

    }

    public Object parseWsOrderStatus(Object status)
    {
        Object statuses = new java.util.HashMap<String, Object>() {{
            put( "open", "open" );
            put( "filled", "closed" );
            put( "match", "open" );
            put( "update", "open" );
            put( "canceled", "canceled" );
            put( "cancel", "canceled" );
            put( "TRIGGERED", "triggered" );
        }};
        return this.safeString(statuses, status, status);
    }

    public Object parseWsOrder(Object order, Object... optionalArgs)
    {
        //
        // /spotMarket/tradeOrders
        //
        //    {
        //        "symbol": "XCAD-USDT",
        //        "orderType": "limit",
        //        "side": "buy",
        //        "orderId": "6249167327218b000135e749",
        //        "type": "canceled",
        //        "orderTime": 1648957043065280224,
        //        "size": "100.452",
        //        "filledSize": "0",
        //        "price": "2.9635",
        //        "clientOid": "buy-XCAD-USDT-1648957043010159",
        //        "remainSize": "0",
        //        "status": "done",
        //        "ts": 1648957054031001037
        //    }
        //
        // /spotMarket/advancedOrders
        //
        //    {
        //        "createdAt": 1589789942337,
        //        "orderId": "5ec244f6a8a75e0009958237",
        //        "orderPrice": "0.00062",
        //        "orderType": "stop",
        //        "side": "sell",
        //        "size": "1",
        //        "stop": "entry",
        //        "stopPrice": "0.00062",
        //        "symbol": "KCS-BTC",
        //        "tradeType": "TRADE",
        //        "triggerSuccess": true,
        //        "ts": 1589790121382281286,
        //        "type": "triggered"
        //    }
        //
        Object market = Helpers.getArg(optionalArgs, 0, null);
        Object rawType = this.safeString(order, "type");
        Object status = this.parseWsOrderStatus(rawType);
        Object timestamp = this.safeInteger2(order, "orderTime", "createdAt");
        Object marketId = this.safeString(order, "symbol");
        market = this.safeMarket(marketId, market);
        Object triggerPrice = this.safeString(order, "stopPrice");
        Object triggerSuccess = this.safeValue(order, "triggerSuccess");
        Object triggerFail = Helpers.isTrue((!Helpers.isEqual(triggerSuccess, true))) && Helpers.isTrue((!Helpers.isEqual(triggerSuccess, null))); // TODO: updated to triggerSuccess === False once transpiler transpiles it correctly
        if (Helpers.isTrue(Helpers.isTrue((Helpers.isEqual(status, "triggered"))) && Helpers.isTrue(triggerFail)))
        {
            status = "canceled";
        }
        final Object finalMarket = market;
        final Object finalStatus = status;
        return this.safeOrder(new java.util.HashMap<String, Object>() {{
            put( "info", order );
            put( "symbol", Helpers.GetValue(finalMarket, "symbol") );
            put( "id", Kucoin.this.safeString(order, "orderId") );
            put( "clientOrderId", Kucoin.this.safeString(order, "clientOid") );
            put( "timestamp", timestamp );
            put( "datetime", Kucoin.this.iso8601(timestamp) );
            put( "lastTradeTimestamp", null );
            put( "type", Kucoin.this.safeStringLower(order, "orderType") );
            put( "timeInForce", null );
            put( "postOnly", null );
            put( "side", Kucoin.this.safeStringLower(order, "side") );
            put( "price", Kucoin.this.safeString2(order, "price", "orderPrice") );
            put( "stopPrice", triggerPrice );
            put( "triggerPrice", triggerPrice );
            put( "amount", Kucoin.this.safeString(order, "size") );
            put( "cost", null );
            put( "average", null );
            put( "filled", Kucoin.this.safeString(order, "filledSize") );
            put( "remaining", null );
            put( "status", finalStatus );
            put( "fee", null );
            put( "trades", null );
        }}, market);
    }

    public void handleOrder(Client client, Object message)
    {
        //
        // Trigger Orders
        //
        //    {
        //        "createdAt": 1692745706437,
        //        "error": "Balance insufficient!",       // not always there
        //        "orderId": "vs86kp757vlda6ni003qs70v",
        //        "orderPrice": "0.26",
        //        "orderType": "stop",
        //        "side": "sell",
        //        "size": "5",
        //        "stop": "loss",
        //        "stopPrice": "0.26",
        //        "symbol": "ADA-USDT",
        //        "tradeType": "TRADE",
        //        "triggerSuccess": false,                // not always there
        //        "ts": "1692745706442929298",
        //        "type": "open"
        //    }
        //
        Object messageHash = "orders";
        Object data = this.safeValue(message, "data");
        Object tradeId = this.safeString(data, "tradeId");
        if (Helpers.isTrue(!Helpers.isEqual(tradeId, null)))
        {
            this.handleMyTrade(client, message);
        }
        Object parsed = this.parseWsOrder(data);
        Object symbol = this.safeString(parsed, "symbol");
        Object orderId = this.safeString(parsed, "id");
        Object triggerPrice = this.safeValue(parsed, "triggerPrice");
        Object isTriggerOrder = (!Helpers.isEqual(triggerPrice, null));
        if (Helpers.isTrue(Helpers.isEqual(this.orders, null)))
        {
            Object limit = this.safeInteger(this.options, "ordersLimit", 1000);
            this.orders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
            this.triggerOrders = new ArrayCache.ArrayCacheBySymbolById(((Number)limit).intValue());
        }
        Object cachedOrders = ((Helpers.isTrue(isTriggerOrder))) ? this.triggerOrders : this.orders;
        Object orders = this.safeValue(((io.github.ccxt.ws.ArrayCache)cachedOrders).hashmap, symbol, new java.util.HashMap<String, Object>() {{}});
        Object order = this.safeValue(orders, orderId);
        if (Helpers.isTrue(!Helpers.isEqual(order, null)))
        {
            // todo add others to calculate average etc
            if (Helpers.isTrue(Helpers.isEqual(Helpers.GetValue(order, "status"), "closed")))
            {
                Helpers.addElementToObject(parsed, "status", "closed");
            }
        }
        Helpers.callDynamically(cachedOrders, "append", new Object[]{parsed});
        client.resolve(cachedOrders, messageHash);
        Object symbolSpecificMessageHash = Helpers.add(Helpers.add(messageHash, ":"), symbol);
        client.resolve(cachedOrders, symbolSpecificMessageHash);
    }

